/**
 * Remove Hugging Face _id so MongoDB can generate ObjectId
 */

return items.map(item => {
  const row = item.json.row;

  if (!row || typeof row !== 'object') {
    return null;
  }

  // Destructure to remove _id
  const { _id, ...doc } = row;

  return {
    json: doc
  };
}).filter(Boolean);
